import React, { useState } from 'react';
import { loginUser } from '../services/api';
import { useAuth } from '../context/AuthContext';
// Stars banane ka function
const generateStars = (count) => {
  return Array.from({ length: count }, (_, i) => ({
    id: i,
    top:  Math.random() * 100,
    left: Math.random() * 100,
    size: Math.random() * 2.5 + 0.5,
    duration: Math.random() * 4 + 2,
    delay: Math.random() * 5,
  }));
};

const STARS = generateStars(120);

const SHOOTING_STARS = [
  { top: 10, left: 5,  delay: 0   },
  { top: 25, left: 40, delay: 4   },
  { top: 60, left: 15, delay: 8   },
  { top: 80, left: 60, delay: 12  },
];

const NEBULAS = [
  { top: 10,  left: 5,  color: 'rgba(34,197,94,0.06)',   size: 500, dur: 25 },
  { top: 60,  left: 60, color: 'rgba(59,130,246,0.05)',  size: 400, dur: 30 },
  { top: 30,  left: 80, color: 'rgba(168,85,247,0.04)',  size: 350, dur: 20 },
  { top: 80,  left: 20, color: 'rgba(249,115,22,0.04)',  size: 300, dur: 35 },
];
function Login() {
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [error, setError]       = useState('');
  const [loading, setLoading]   = useState(false);
  const [focused, setFocused]   = useState('');

  const { login } = useAuth();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await loginUser({ email, password });
      login(res.data.token, res.data.user);
      window.location.href = '/dashboard';
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.page}>
      {/* Background glow effects */}
      <div style={s.glowTop}></div>
      <div style={s.glowBottom}></div>

      {/* Left Panel */}
      <div style={s.left}>
        <div style={s.logo}>
          <span style={s.owl}>🦉</span>
          <span style={s.logoText}>DevNest</span>
          <span style={s.betaBadge}>BETA</span>
        </div>

        <div style={s.heroText}>
          <h1 style={s.headline}>
            Track. Build.<br />
            <span style={s.highlight}>Get Hired.</span>
          </h1>
          <p style={s.subtext}>
            The only platform that combines DSA tracking,
            GitHub analytics, and AI-powered interview prep.
          </p>
        </div>

        <div style={s.statsRow}>
          {[
            { num: '25+', label: 'DSA Problems' },
            { num: 'AI', label: 'Powered Mentor' },
            { num: '1', label: 'Platform' },
          ].map(stat => (
            <div key={stat.label} style={s.statBox}>
              <div style={s.statNum}>{stat.num}</div>
              <div style={s.statLabel}>{stat.label}</div>
            </div>
          ))}
        </div>

        <div style={s.featureList}>
          {[
            { icon: '📊', text: 'DSA Sheet Tracker — Striver, Blind 75' },
            { icon: '🐙', text: 'GitHub Analytics — Repos, Heatmap' },
            { icon: '🤖', text: 'AI Coding Mentor — Personalized roadmap' },
            { icon: '🎯', text: 'Interview Readiness Score per company' },
          ].map(f => (
            <div key={f.text} style={s.featureItem}>
              <span style={s.featureIcon}>{f.icon}</span>
              <span style={s.featureText}>{f.text}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Right Panel */}
      <div style={s.right}>
        <div style={s.card}>
          {/* Card glow */}
          <div style={s.cardGlow}></div>

          <div style={s.cardHeader}>
            <h2 style={s.cardTitle}>Welcome back 👋</h2>
            <p style={s.cardSub}>Login to continue your journey</p>
          </div>

          {error && (
            <div style={s.errorBox}>
              <span>⚠️</span> {error}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            <div style={s.field}>
              <label style={s.label}>Email address</label>
              <div style={{
                ...s.inputWrap,
                borderColor: focused === 'email' ? '#22c55e' : '#2a2a2a'
              }}>
                <span style={s.inputIcon}>✉️</span>
                <input
                  style={s.input}
                  type="email"
                  placeholder="shrey@gmail.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  onFocus={() => setFocused('email')}
                  onBlur={() => setFocused('')}
                  required
                />
              </div>
            </div>

            <div style={s.field}>
              <label style={s.label}>Password</label>
              <div style={{
                ...s.inputWrap,
                borderColor: focused === 'password' ? '#22c55e' : '#2a2a2a'
              }}>
                <span style={s.inputIcon}>🔒</span>
                <input
                  style={s.input}
                  type="password"
                  placeholder="••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  onFocus={() => setFocused('password')}
                  onBlur={() => setFocused('')}
                  required
                />
              </div>
            </div>

            <button
              type="submit"
              style={loading ? {...s.btn, opacity: 0.75} : s.btn}
              disabled={loading}
            >
              {loading ? (
                <span>Logging in...</span>
              ) : (
                <span>Continue to DevNest →</span>
              )}
            </button>
          </form>

          <div style={s.divider}>
            <div style={s.dividerLine}></div>
            <span style={s.dividerText}>or</span>
            <div style={s.dividerLine}></div>
          </div>

          <p style={s.bottomText}>
            Naya account?{' '}
            <a href="/register" style={s.link}>Register karo — free hai!</a>
          </p>
        </div>
      </div>
    </div>
  );
}

